import{_ as n,C as o,o as s,c as l,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Austria","description":"Immigration pathways and relocation guide for Austria","frontmatter":{"layout":"doc","title":"Moving to Austria","description":"Immigration pathways and relocation guide for Austria"},"headers":[],"relativePath":"europe/austria/moving-there.md","filePath":"europe/austria/moving-there.md","lastUpdated":null}'),h={name:"europe/austria/moving-there.md"};function g(u,t,c,m,f,p){const e=o("Badge");return s(),l("div",null,[r(e,{variant:"green"},{default:a(()=>[...t[0]||(t[0]=[i("EU Free Movement",-1)])]),_:1}),r(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[i("Red-White-Red Card",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-austria" tabindex="-1">Moving to Austria <a class="header-anchor" href="#moving-to-austria" aria-label="Permalink to &quot;Moving to Austria&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Austria grants full <strong>free movement rights</strong> to EU/EEA/Swiss citizens:</p><ul><li><strong>Up to 3 months</strong>: No registration required</li><li><strong>Over 3 months</strong>: Must register with the municipal office (Meldeamt) and obtain an <strong>Anmeldebescheinigung</strong> (registration certificate)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>After 5 years</strong>: Eligible for permanent residence (Daueraufenthalt)</li><li><strong>After 6-10 years</strong>: Eligible for Austrian citizenship (requires German language B2, citizenship test)</li></ul><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><p>The <strong>Red-White-Red Card</strong> system is the main immigration pathway:</p><table tabindex="0"><thead><tr><th>Card Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Red-White-Red Card</td><td>Work permit</td><td>Job offer, minimum salary (€3,000+/month gross), degree</td><td>2 years, renewable</td></tr><tr><td>Red-White-Red Card (Key Worker)</td><td>Highly skilled workers</td><td>Degree in high-demand field, salary threshold</td><td>2 years, renewable</td></tr><tr><td>Red-White-Red Card (Start-up)</td><td>Founders</td><td>Innovative business plan, 50,000+ EUR funds</td><td>2 years, renewable</td></tr><tr><td>Red-White-Red Card Plus</td><td>Free job mobility</td><td>After 5 years or for family members</td><td>Unlimited</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof (€6,000+/year)</td><td>1 year, renewable</td></tr><tr><td>Family Reunification</td><td>Family of residents</td><td>Relationship proof, accommodation, health insurance</td><td>1 year, renewable</td></tr><tr><td>EU Blue Card</td><td>Highly qualified</td><td>Degree + salary ≥ €60,000+/year</td><td>2 years, renewable</td></tr></tbody></table><h3 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h3><p>Austria does <strong>not</strong> have a specific digital nomad visa. Remote workers can:</p><ul><li>Apply for a <strong>Red-White-Red Card</strong> if employed by an Austrian company</li><li><strong>Freelancer visa</strong>: Available for self-employed individuals with Austrian clients</li><li><strong>Residence permit for exceptional circumstances</strong>: Limited options for remote workers</li><li>Many remote workers use EU citizenship or the start-up visa route</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa/Residence</strong>: Check requirements for your nationality</li><li>[ ] <strong>Health Insurance</strong>: Mandatory — register with Austrian social insurance (ÖGK)</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (German preferred)</li><li>[ ] <strong>Medical Records</strong>: Translated into German</li><li>[ ] <strong>Banking</strong>: International banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (willhaben.at, immobilienscout24.at)</li><li>[ ] <strong>Language</strong>: German is essential for integration</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] <strong>Register address</strong> at the Meldeamt (within 3 days!)</li><li>[ ] <strong>Apply for residence permit</strong> (EU citizens: get Anmeldebescheinigung)</li><li>[ ] <strong>Get social insurance</strong> through employer or ÖGK</li><li>[ ] <strong>Open bank account</strong> — Erste Bank, Raiffeisen, Bank Austria</li><li>[ ] <strong>Get e-card</strong> (health insurance card)</li><li>[ ] <strong>Register with AKH Genderambulanz</strong> if in Vienna</li><li>[ ] <strong>Connect with HOSI Wien</strong> for LGBTQ+ community</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Vienna</th><th>Other Cities</th></tr></thead><tbody><tr><td>Rent (1-bedroom)</td><td>€800-1,300/month</td><td>€500-900/month</td></tr><tr><td>Groceries</td><td>€250-400/month</td><td>€220-350/month</td></tr><tr><td>Public transport</td><td>€33/month (annual pass)</td><td>€30-50/month</td></tr><tr><td>Health insurance</td><td>Social insurance included</td><td>Social insurance included</td></tr><tr><td>Utilities</td><td>€150-250/month</td><td>€120-200/month</td></tr></tbody></table><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li><strong>Official language</strong>: German</li><li><strong>English</strong>: Widely spoken in Vienna, especially in business and tech</li><li><strong>Integration</strong>: German B1 recommended for daily life, B2 required for citizenship</li><li>Free German courses available through integration programs</li><li>Viennese dialect is distinct from standard German</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Continental climate</strong>: Cold winters, warm summers</li><li><strong>Winter</strong>: -5°C to 5°C (December-February)</li><li><strong>Summer</strong>: 15°C to 30°C (June-August)</li><li><strong>Best time to arrive</strong>: Spring (March-May) or early autumn</li></ul><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>Vienna is the most trans-friendly city</strong> — AKH Genderambulanz provides excellent care</li><li>Graz, Linz, and Salzburg are generally accepting</li><li>Rural and conservative areas (Styria, Carinthia, Tyrol) may be less welcoming</li><li>Self-ID law (2024) is a major positive</li><li><strong>HOSI Wien</strong> offers community support</li><li>Trans* Austria provides advocacy and resources</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.migration.gv.at/" target="_blank" rel="noreferrer">OeMA - Austrian Migration Agency</a></li><li><a href="https://www.oegk.at/" target="_blank" rel="noreferrer">ÖGK - Austrian Health Insurance</a></li><li><a href="https://www.willhaben.at/" target="_blank" rel="noreferrer">Willhaben - Housing</a></li><li><a href="https://www.hosiwien.at/" target="_blank" rel="noreferrer">HOSI Wien</a></li><li><a href="https://trans-austria.org/" target="_blank" rel="noreferrer">Trans* Austria</a></li><li><a href="https://vimoe.at/" target="_blank" rel="noreferrer">VIMÖ</a></li></ul>',27))])}const v=n(h,[["render",g]]);export{y as __pageData,v as default};
